int counter = 0;
int buttonPin = 12;
int lastButtonState = HIGH;
unsigned long lastDebounceTime = 0;
unsigned long debounceDelay = 50;

// Segment pins: a, b, c, d, e, f, g
int segmentPins[7] = {2, 3, 4, 5, 6, 7, 8};

void setup() {
  pinMode(buttonPin, INPUT_PULLUP);
  for (int i = 0; i < 7; i++) {
    pinMode(segmentPins[i], OUTPUT);
  }
  displayDigit(0);
}

void loop() {
  int buttonState = digitalRead(buttonPin);

  if (buttonState != lastButtonState) {
    lastDebounceTime = millis();
  }

  if ((millis() - lastDebounceTime) > debounceDelay) {
    if (buttonState == LOW && lastButtonState == HIGH) {
      counter++;
      if (counter > 9) {
        counter = 0;
      }
      displayDigit(counter);
    }
  }

  lastButtonState = buttonState;
}

void displayDigit(int digit) {
  if (digit == 0) {
    setSegments(1, 1, 1, 1, 1, 1, 0);
  } else if (digit == 1) {
    setSegments(0, 1, 1, 0, 0, 0, 0);
  } else if (digit == 2) {
    setSegments(1, 1, 0, 1, 1, 0, 1);
  } else if (digit == 3) {
    setSegments(1, 1, 1, 1, 0, 0, 1);
  } else if (digit == 4) {
    setSegments(0, 1, 1, 0, 0, 1, 1);
  } else if (digit == 5) {
    setSegments(1, 0, 1, 1, 0, 1, 1);
  } else if (digit == 6) {
    setSegments(1, 0, 1, 1, 1, 1, 1);
  } else if (digit == 7) {
    setSegments(1, 1, 1, 0, 0, 0, 0);
  } else if (digit == 8) {
    setSegments(1, 1, 1, 1, 1, 1, 1);
  } else if (digit == 9) {
    setSegments(1, 1, 1, 1, 0, 1, 1);
  }
}

void setSegments(int a, int b, int c, int d, int e, int f, int g) {
  digitalWrite(2, a);
  digitalWrite(3, b);
  digitalWrite(4, c);
  digitalWrite(5, d);
  digitalWrite(6, e);
  digitalWrite(7, f);
  digitalWrite(8, g);
}

